from typing import List

def solve(grid: List[List[int]], k: int) -> int:
    if not grid or not grid[0]:
        return 0

    m, n = len(grid), len(grid[0])
    visited = [[False for _ in range(n)] for _ in range(m)]
    count = 0

    def dfs(i: int, j: int) -> int:
        if i < 0 or i >= m or j < 0 or j >= n or grid[i][j] == 0 or visited[i][j]:
            return 0
        visited[i][j] = True
        total = grid[i][j]
        total += dfs(i + 1, j)
        total += dfs(i - 1, j)
        total += dfs(i, j + 1)
        total += dfs(i, j - 1)
        return total

    for i in range(m):
        for j in range(n):
            if grid[i][j] != 0 and not visited[i][j]:
                island_sum = dfs(i, j)
                if island_sum % k == 0:
                    count += 1

    return count
